const f = $('Extrair_Validar').item.json;
const raw = $input.item.json;
const arr = Array.isArray(raw) ? raw : [raw];
const interpretacao = arr[0]?.content?.parts?.[0]?.text || '(Não foi possível interpretar o edital)';

const originalBinary = $('Download_PDF').item.binary;
const fixedBinary = {};
for (const key of Object.keys(originalBinary)) {
  fixedBinary[key] = {
    ...originalBinary[key],
    fileName: 'edital.pdf',
    mimeType: 'application/pdf',
  };
}

return { json: { ...f, interpretacao }, binary: fixedBinary };

